import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RecentContact {
  name: string;
  lastMessage: string;
}

interface MessageVolume {
  hour: string;
  messages: number;
}

interface MessagingData {
  unreadConversations: number;
  recentContacts: RecentContact[];
  messageVolume: MessageVolume[];
}

export default function Widget() {
  const messagingData = response.data as MessagingData;
  const { unreadConversations, recentContacts, messageVolume } = messagingData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#4CAF50' }}>
              QuickChat Overview
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Unread Conversations: {unreadConversations}
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {recentContacts.map((contact, index) => (
                <Box key={index}>
                  <Typography variant="body2" fontWeight={500} sx={{ color: '#FF9800' }}>
                    {contact.name}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {contact.lastMessage}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <BarChart
            height={120}
            series={[
              {
                data: messageVolume.map((m) => m.messages),
                color: '#4CAF50',
              },
            ]}
            xAxis={[
              {
                data: messageVolume.map((m) => m.hour),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
